import React, { useState, useEffect } from 'react';
import { getMovieDetails } from '../../services/Api';

const MoviePopup = ({ movie, onClose, onDelete, onUpdate }) => {
    const [details, setDetails] = useState(null);
    const [isEditing, setIsEditing] = useState(false);
    const [newTitle, setNewTitle] = useState(movie.title || '');

    useEffect(() => {
        const fetchInfo = async () => {
            const data = await getMovieDetails(movie.imdbID || movie.id);
            // Prioritize the edited title from state over the API title
            setDetails({ ...data, Title: movie.title || data.Title });
            setNewTitle(movie.title || data.Title);
        };
        if (movie) fetchInfo();

        // Fixes: Line 21:8: React Hook useEffect has a missing dependency
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [movie]);

    const handleSave = () => {
        onUpdate(movie.imdbID || movie.id, newTitle);
        setIsEditing(false);
    };

    const handleKeyDown = (e) => {
        if (e.key === 'Enter') handleSave();
        if (e.key === 'Escape') setIsEditing(false);
    };

    if (!details) return null;

    return (
        <div className="popup-overlay" onClick={onClose}>
            <div className="popup-content" onClick={(e) => e.stopPropagation()}>
                <button className="close-btn" onClick={onClose}>×</button>
                <div className="popup-layout">
                    <img src={movie.poster} alt={movie.title} />
                    <div className="popup-info">
                        {isEditing ? (
                            <div className="edit-container">
                                <input
                                    autoFocus
                                    type="text"
                                    value={newTitle}
                                    onChange={(e) => setNewTitle(e.target.value)}
                                    onKeyDown={handleKeyDown}
                                    className="edit-input"
                                />
                                <button onClick={handleSave} className="btn-save">Save</button>
                            </div>
                        ) : (
                            <h2 onClick={() => setIsEditing(true)} style={{ cursor: 'pointer' }}>
                                {movie.title} ✎
                            </h2>
                        )}
                        <p className="meta">{details.Year} • {details.Genre} • {details.Runtime}</p>
                        <p className="plot">{details.Plot}</p>
                        <div className="popup-actions">
                            <button className="btn-delete" onClick={() => onDelete(movie.id || movie.imdbID)}>
                                Delete from List
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default MoviePopup;
